import ls from 'local-storage'

const leagueKey = 'currentLeague'

const currentLeague = () => {
  return ls.get(leagueKey) || '11'
}

const setLeague = (league) => {
  ls.set(leagueKey, league)
}

const Leagues = [
  { id: 11, name: "Parity Tournament 2020" }
]

export {
  currentLeague,
  setLeague,
  Leagues
}
